import React, { useState, useEffect } from 'react';
import { Link } from 'react-router-dom';
import axios from 'axios';
import './Home.css';

function Home() {
  const [searchQuery, setSearchQuery] = useState('');
  const [categories, setCategories] = useState([]);
  const [featuredProducts, setFeaturedProducts] = useState([]);
  const [stats, setStats] = useState({ products: 0, suppliers: 0, categories: 0 });

  useEffect(() => {
    fetchCategories();
    fetchFeaturedProducts();
    fetchStats();
  }, []);

  const fetchCategories = async () => {
    try {
      const response = await axios.get('/api/categories');
      setCategories(response.data.slice(0, 8));
    } catch (error) {
      console.error('Error fetching categories:', error);
    }
  };

  const fetchFeaturedProducts = async () => {
    try {
      const response = await axios.get('/api/products?featured=true&limit=8');
      setFeaturedProducts(response.data);
    } catch (error) {
      console.error('Error fetching featured products:', error);
    }
  };

  const fetchStats = async () => {
    try {
      const response = await axios.get('/api/stats');
      setStats(response.data);
    } catch (error) {
      console.error('Error fetching stats:', error);
    }
  };

  const handleSearch = (e) => {
    e.preventDefault();
    if (searchQuery.trim()) {
      window.location.href = `/products?search=${encodeURIComponent(searchQuery)}`;
    }
  };

  return (
    <div className="home">
      <section className="hero">
        <div className="hero-content">
          <h1>India's Largest B2B Marketplace</h1>
          <p>Connect with Manufacturers, Suppliers & Exporters Worldwide</p>
          <form onSubmit={handleSearch} className="search-box">
            <input
              type="text"
              placeholder="Search products, suppliers, companies..."
              value={searchQuery}
              onChange={(e) => setSearchQuery(e.target.value)}
              className="search-input"
            />
            <button type="submit" className="search-btn">Search</button>
          </form>
        </div>
      </section>

      <section className="stats-section">
        <div className="container">
          <div className="stats-grid">
            <div className="stat-item">
              <h3>{stats.products.toLocaleString()}+</h3>
              <p>Products</p>
            </div>
            <div className="stat-item">
              <h3>{stats.suppliers.toLocaleString()}+</h3>
              <p>Suppliers</p>
            </div>
            <div className="stat-item">
              <h3>{stats.categories.toLocaleString()}+</h3>
              <p>Categories</p>
            </div>
          </div>
        </div>
      </section>

      <section className="categories-section">
        <div className="container">
          <h2 className="section-title">Browse by Category</h2>
          <div className="categories-grid">
            {categories.map((category) => (
              <Link
                key={category.id}
                to={`/products?category=${category.id}`}
                className="category-card"
              >
                <div className="category-icon">{category.name.charAt(0)}</div>
                <h3>{category.name}</h3>
              </Link>
            ))}
          </div>
        </div>
      </section>

      <section className="featured-products-section">
        <div className="container">
          <h2 className="section-title">Featured Products</h2>
          <div className="products-grid">
            {featuredProducts.map((product) => (
              <Link
                key={product.id}
                to={`/products/${product.id}`}
                className="product-card"
              >
                <div className="product-image">
                  {product.image_url ? (
                    <img src={product.image_url} alt={product.name} />
                  ) : (
                    <div className="product-placeholder">No Image</div>
                  )}
                </div>
                <div className="product-info">
                  <h3>{product.name}</h3>
                  <p className="product-price">₹{product.price?.toLocaleString() || 'Price on Request'}</p>
                  <p className="product-supplier">{product.company_name}</p>
                </div>
              </Link>
            ))}
          </div>
          <div className="section-footer">
            <Link to="/products" className="btn btn-outline">View All Products</Link>
          </div>
        </div>
      </section>
    </div>
  );
}

export default Home;
